cd "C:/Users/EDY/AppData/Local/Temp/claude/D--nexgaios-amazon/75bfbc79-d177-409b-9ee2-61bd87ae42dd/scratchpad" && python -c "
import csv,os
la=list(csv.DictReader(open('lingxing_snapshot/asin_monthly.csv',encoding='utf-8-sig')))
m26=['2026-02','2026-03','2026-04','2026-05','2026-06']
m26_nojan=m26
models={}
for r in la:
    models.setdefault(r['model'],[]).append(r)
print('Feb-Jun 2026 net-amount-weighted gross_margin:')
for model,rows in models.items():
    num=sum(float(r['net_amount'])*float(r['gross_margin']) for r in rows if r['month'] in m26)
    den=sum(float(r['net_amount']) for r in rows if r['month'] in m26)
    if den>0: print(f'  {model}: {num/den*100:.1f}%  (net \${den:,.0f})')
# X2 unit net price stability
print()
x2=[r for r in la if r['model']=='Break X2']
for r in x2:
    if int(r['volume'])>0:
        print(f\"  X2 {r['month']}: net/vol=\${float(r['net_amount'])/int(r['volume']):.0f}\")
